import { useEffect, useState } from 'react';

const WISHLIST_STORAGE_KEY = 'wishlistItems';

export const useWishlist = () => {
    const [items, setItems] = useState([]);

    // Load wishlist from localStorage on mount
    useEffect(() => {
        if (typeof window === 'undefined') return;

        const storedWishlist = localStorage.getItem(WISHLIST_STORAGE_KEY);
        if (storedWishlist) {
            try {
                setItems(JSON.parse(storedWishlist));
            } catch (error) {
                console.warn('Failed to parse wishlist from localStorage:', error);
                setItems([]);
            }
        }
    }, []);

    // Add item to wishlist
    const addItem = (productId, variantId, name, price, image) => {
        setItems((currentItems) => {
            // Check if item already exists
            const exists = currentItems.some(
                (item) => item.productId === productId && item.variantId === variantId
            );

            if (exists) {
                return currentItems; // Item already in wishlist
            }

            const newItem = {
                productId,
                variantId,
                name,
                price,
                image,
            };

            const updated = [...currentItems, newItem];
            if (typeof window !== 'undefined') {
                localStorage.setItem(WISHLIST_STORAGE_KEY, JSON.stringify(updated));
            }
            return updated;
        });
    };

    // Remove item from wishlist
    const removeItem = (productId, variantId) => {
        setItems((currentItems) => {
            const updated = currentItems.filter(
                (item) => !(item.productId === productId && item.variantId === variantId)
            );
            if (typeof window !== 'undefined') {
                localStorage.setItem(WISHLIST_STORAGE_KEY, JSON.stringify(updated));
            }
            return updated;
        });
    };

    // Check if item is in wishlist
    const isInWishlist = (productId, variantId) => {
        return items.some(
            (item) => item.productId === productId && item.variantId === variantId
        );
    };

    return {
        items,
        addItem,
        removeItem,
        isInWishlist,
    };
};
